/*
Emitted when any setting is changed, up to once per process frame.
*/
func OnSettingsChanged(cb func(), flags ...Signal.Flags) {
	var flags_together Signal.Flags
	for _, flag := range flags {
		flags_together |= flag
	}
	once.Do(singleton)
	gdclass.GetProjectSettings(self[0])[0].Connect(gd.NewStringName("settings_changed"), gd.NewCallable(cb), int64(flags_together))
}

func (self class) SettingsChanged() Signal.Any {
	once.Do(singleton)
	return Signal.Via(gd.SignalProxy{}, pointers.Pack(gd.NewSignalOf(self.AsObject(), gd.NewStringName(`settings_changed`))))
}

func (self class) Virtual(name string) reflect.Value {
	switch name {
	default:
		return gd.VirtualByName(Object.Advanced(self.AsObject()), name)
	}
}

func (self Instance) Virtual(name string) reflect.Value {
	switch name {
	default:
		return gd.VirtualByName(Object.Instance(self.AsObject()), name)
	}
}
func init() {
	gdclass.Register("ProjectSettings", func(ptr gd.Object) any { return Instance{gdclass.NewProjectSettings(ptr)} })
}

